package cn.edu.agent.core;

import cn.edu.agent.compact.ContextCompactor;
import cn.edu.agent.config.AppConfig;
import cn.edu.agent.monitor.MonitorLogger;
import cn.edu.agent.pojo.AgentContext;
import cn.edu.agent.pojo.ContentBlock;
import cn.edu.agent.pojo.LlmResponse;
import cn.edu.agent.tool.AgentTool;
import cn.edu.agent.tool.AgentRole;
import cn.edu.agent.tool.ToolManager;
import cn.edu.agent.tool.impl.CompactTool;

import java.util.*;

// AgentLoop 是整个 Agent 的核心循环，负责管理对话历史、调用 LLM、执行工具，并根据 LLM 的回复决定下一步行动。
public class AgentLoop {
    private final LlmClient llmClient;
    private final ToolManager toolManager;
    private final String systemPrompt;
    private final List<Map<String, Object>> chatHistory = new ArrayList<>();

    // s06：上下文压缩器
    private final ContextCompactor compactor = new ContextCompactor();

    public AgentLoop() {
        this(new ToolManager(), "你是 Claude，一个高级软工 AI 助手。你可以使用工具来完成任务。");
    }

    public AgentLoop(ToolManager toolManager) {
        this(toolManager, "你是 Claude，一个高级软工 AI 助手。你可以使用工具来完成任务。");
    }

    public AgentLoop(ToolManager toolManager, String systemPrompt) {
        this.llmClient = new LlmClient();
        this.toolManager = toolManager;
        this.systemPrompt = systemPrompt;
    }

    public void start() {
        Scanner scanner = new Scanner(System.in);
        System.out.println(" [Claude Agent Java Edition] 已启动! (s06: context compact)");

        while (true) {
            System.out.print("\n你 >> ");
            String userInput = scanner.nextLine().trim();
            if ("exit".equalsIgnoreCase(userInput)) {
                MonitorLogger.flushToFile();
                break;
            }
            if ("/stats".equalsIgnoreCase(userInput)) {
                MonitorLogger.printStats();
                continue;
            }

            String contentForHistory = toolManager.prefixUserMessageIfNeeded(userInput);
            chatHistory.add(Map.of("role", "user", "content", contentForHistory));

            runAgentCycle();
        }
    }

    // Agent 的自主思考循环（集成三层压缩）
    private void runAgentCycle() {
        boolean turnFinished = false;

        while (!turnFinished) {
            try {
                // ── Layer 1：每轮静默执行 micro compact ──
                int keepRecent = AppConfig.getCompactKeepRecent();
                int beforeLayer1 = compactor.estimateTokens(chatHistory);
                compactor.microCompact(chatHistory, keepRecent);
                int afterLayer1 = compactor.estimateTokens(chatHistory);
                System.out.println(String.format("[TOKEN] Layer1 前: %d tokens, Layer1 后: %d tokens, 压缩: %d tokens (%.1f%%)",
                        beforeLayer1, afterLayer1, beforeLayer1 - afterLayer1,
                        beforeLayer1 > 0 ? (beforeLayer1 - afterLayer1) * 100.0 / beforeLayer1 : 0));

                // ── Layer 2：token 超阈值时自动压缩 ──
                int threshold = AppConfig.getCompactTokenThreshold();
                if (compactor.estimateTokens(chatHistory) > threshold) {
                    int beforeLayer2 = compactor.estimateTokens(chatHistory);
                    System.out.println("[AgentLoop] token 超阈值，触发 Layer 2 自动压缩...");
                    List<Map<String, Object>> compressed = compactor.autoCompact(chatHistory);
                    chatHistory.clear();
                    chatHistory.addAll(compressed);
                    int afterLayer2 = compactor.estimateTokens(chatHistory);
                    System.out.println(String.format("[TOKEN] Layer2 压缩: %d → %d tokens (压缩率 %.1f%%)",
                            beforeLayer2, afterLayer2, (beforeLayer2 - afterLayer2) * 100.0 / beforeLayer2));
                }

                LlmResponse response = llmClient.call(
                        chatHistory,
                        toolManager.getToolsForLlm(AgentRole.PARENT),
                        systemPrompt
                );

                chatHistory.add(Map.of("role", "assistant", "content", response.getContent()));

                if ("tool_use".equals(response.getStopReason())) {
                    List<Map<String, Object>> toolResults = new ArrayList<>();

                    for (ContentBlock block : response.getContent()) {
                        if ("text".equals(block.getType()) && block.getText() != null) {
                            System.out.println("🤔 思考: " + block.getText());
                        } else if ("tool_use".equals(block.getType())) {
                            AgentTool tool = toolManager.getTool(block.getName());
                            String toolName = block.getName();
                            if ("todo".equals(toolName) || toolName.startsWith("task_")) {
                                toolManager.resetTodoCounter();
                            }

                            String toolOutput;
                            if (tool != null) {
                                toolOutput = tool.execute(block.getInput());
                            } else {
                                toolOutput = "Error: Tool " + block.getName() + " not found.";
                            }

                            // ── Layer 3：LLM 主动触发压缩 ──
                            if (CompactTool.COMPACT_SIGNAL.equals(toolOutput)) {
                                System.out.println("[AgentLoop] 收到 compact 信号，触发 Layer 3 强制压缩...");
                                List<Map<String, Object>> compressed = compactor.autoCompact(chatHistory);
                                chatHistory.clear();
                                chatHistory.addAll(compressed);
                                toolOutput = "[Context compacted successfully]";
                            }

                            System.out.println("    输出: \n" + toolOutput);
                            toolResults.add(Map.of(
                                    "type", "tool_result",
                                    "tool_use_id", block.getId(),
                                    "content", toolOutput
                            ));
                        }
                    }
                    chatHistory.add(Map.of("role", "user", "content", toolResults));

                    toolManager.incrementRoundCounter();
                } else {
                    toolManager.incrementRoundCounter();
                    for (ContentBlock block : response.getContent()) {
                        if ("text".equals(block.getType())) {
                            System.out.println("Claude >> " + block.getText());
                        }
                    }
                    turnFinished = true;
                }
            } catch (Exception e) {
                System.err.println("❌ 发生错误: " + e.getMessage());
                turnFinished = true;
            }
        }
    }
}

package cn.edu.agent.config;

import io.github.cdimascio.dotenv.Dotenv;

public class AppConfig {
    // 单例模式加载 dotenv
    private static final Dotenv dotenv = Dotenv.configure()
            .ignoreIfMissing() // 如果没找到文件不报错
            .load();

    private static String getEnv(String key, String defaultValue) {
        String systemEnv = System.getenv(key);
        if (systemEnv != null && !systemEnv.isBlank()) {
            return systemEnv;
        }
        return dotenv.get(key, defaultValue);
    }

    public static String getApiKey() {
        return getEnv("ANTHROPIC_API_KEY", null);
    }

    public static String getBaseUrl() {
        return getEnv("ANTHROPIC_BASE_URL", "https://api.anthropic.com/v1");
    }

    public static String getModelId() {
        return getEnv("MODEL_ID", "claude-3-5-sonnet-20240620");
    }

    public static int getSubagentMaxIterations() {
        return Integer.parseInt(getEnv("SUBAGENT_MAX_ITERATIONS", "30"));
    }

    public static int getCompactTokenThreshold() {
        return Integer.parseInt(getEnv("COMPACT_TOKEN_THRESHOLD", "50000"));
    }

    public static int getCompactKeepRecent() {
        return Integer.parseInt(getEnv("COMPACT_KEEP_RECENT", "3"));
    }

    public static String getTranscriptDir() {
        return getEnv("TRANSCRIPT_DIR", ".transcripts");
    }

    /** 返回 MCP server 启动命令，未配置则返回 null */
    public static String getMcpCommand() {
        return getEnv("MCP_COMMAND", null);
    }
}

package cn.edu.agent.compact;

import cn.edu.agent.config.AppConfig;
import cn.edu.agent.core.LlmClient;
import cn.edu.agent.pojo.LlmResponse;
import cn.edu.agent.pojo.ContentBlock;

import java.util.*;

/**
 * 三层上下文压缩器
 * Layer 1 — microCompact：静默替换旧 tool_result，每轮必执行
 * Layer 2 — autoCompact：token 超阈值时调用 LLM 生成摘要，整体替换
 * Layer 3 — 由 CompactTool 触发，逻辑同 Layer 2
 */
public class ContextCompactor {

    private final LlmClient llmClient;
    private final TranscriptManager transcriptManager;

    public ContextCompactor() {
        this.llmClient = new LlmClient();
        this.transcriptManager = new TranscriptManager();
    }

    /**
     * Layer 1 — Micro Compact（静默，每轮必执行）
     * 将超过 keepRecent 轮的旧 tool_result 替换为占位符，
     * 只保留最近 keepRecent 条 tool_result 的完整内容。
     *
     * @param messages   当前完整对话历史（原地修改）
     * @param keepRecent 保留最近几条 tool_result 不压缩（默认 3）
     * @return 压缩后的消息列表（同一引用）
     */
    @SuppressWarnings("unchecked")
    public List<Map<String, Object>> microCompact(List<Map<String, Object>> messages, int keepRecent) {
        // 收集所有包含 tool_result 的 user 消息（content 为 List 类型）
        List<Map<String, Object>> toolResultMessages = new ArrayList<>();
        for (Map<String, Object> msg : messages) {
            if ("user".equals(msg.get("role")) && msg.get("content") instanceof List) {
                List<Object> contentList = (List<Object>) msg.get("content");
                boolean hasToolResult = contentList.stream()
                        .anyMatch(item -> item instanceof Map
                                && "tool_result".equals(((Map<Object, Object>) item).get("type")));
                if (hasToolResult) {
                    toolResultMessages.add(msg);
                }
            }
        }

        // 只压缩超出 keepRecent 的旧消息
        int totalToolResultMsgs = toolResultMessages.size();
        int compressCount = Math.max(0, totalToolResultMsgs - keepRecent);

        for (int i = 0; i < compressCount; i++) {
            Map<String, Object> msg = toolResultMessages.get(i);
            List<Object> contentList = (List<Object>) msg.get("content");
            List<Object> compressedContent = new ArrayList<>();

            for (Object item : contentList) {
                if (item instanceof Map) {
                    Map<String, Object> block = (Map<String, Object>) item;
                    if ("tool_result".equals(block.get("type"))) {
                        // 替换为占位符，保留 tool_use_id
                        String toolName = (String) block.getOrDefault("name", "tool");
                        Map<String, Object> placeholder = new LinkedHashMap<>();
                        placeholder.put("type", "tool_result");
                        placeholder.put("tool_use_id", block.get("tool_use_id"));
                        placeholder.put("content", "[Previous: used " + toolName + "]");
                        compressedContent.add(placeholder);
                    } else {
                        compressedContent.add(item);
                    }
                } else {
                    compressedContent.add(item);
                }
            }

            // 原地替换 content（需要可变 Map）
            Map<String, Object> mutableMsg = new LinkedHashMap<>(msg);
            mutableMsg.put("content", compressedContent);
            int idx = messages.indexOf(msg);
            if (idx >= 0) {
                messages.set(idx, mutableMsg);
            }
        }

        return messages;
    }

    /**
     * Layer 2 — Auto Compact（token 超阈值时触发）
     * 1. 调用 TranscriptManager 将完整历史落盘
     * 2. 调用 LlmClient 对历史做摘要
     * 3. 返回只含一条 [Compressed] 摘要消息的新列表
     *
     * @param messages 当前完整对话历史
     * @return 压缩后的单条摘要消息列表
     */
    public List<Map<String, Object>> autoCompact(List<Map<String, Object>> messages) throws Exception {
        // Step 1：落盘完整历史
        String transcriptDir = AppConfig.getTranscriptDir();
        try {
            String savedPath = transcriptManager.save(messages, transcriptDir);
            System.out.println("📁 对话历史已落盘: " + savedPath);
        } catch (Exception e) {
            System.err.println("⚠️ 落盘失败（继续压缩）: " + e.getMessage());
        }

        // Step 2：构造摘要请求
        String summaryPrompt = buildSummaryPrompt(messages);
        List<Map<String, Object>> summaryMessages = new ArrayList<>();
        summaryMessages.add(Map.of("role", "user", "content", summaryPrompt));

        // Step 3：调用 LLM 生成摘要
        String summary;
        try {
            LlmResponse response = llmClient.call(summaryMessages, Collections.emptyList(),
                    "你是一个对话历史压缩助手。请将以下对话历史压缩为简洁的摘要，保留关键进度、决策和待办事项。");
            StringBuilder sb = new StringBuilder();
            if (response.getContent() != null) {
                for (ContentBlock block : response.getContent()) {
                    if ("text".equals(block.getType()) && block.getText() != null) {
                        sb.append(block.getText());
                    }
                }
            }
            summary = sb.toString().trim();
            if (summary.isEmpty()) {
                summary = "（对话历史已压缩，摘要生成失败）";
            }
        } catch (Exception e) {
            System.err.println("⚠️ LLM 摘要失败，使用简单摘要: " + e.getMessage());
            summary = "（对话历史已压缩，共 " + messages.size() + " 条消息）";
        }

        // Step 4：返回单条摘要消息
        List<Map<String, Object>> result = new ArrayList<>();
        result.add(Map.of("role", "user", "content", "[Compressed]\n\n" + summary));
        return result;
    }

    /**
     * 估算消息列表的 token 数（粗估：字符数 / 4）
     *
     * @param messages 消息列表
     * @return 估算 token 数
     */
    public int estimateTokens(List<Map<String, Object>> messages) {
        int charCount = 0;
        for (Map<String, Object> msg : messages) {
            charCount += toCharCount(msg);
        }
        return charCount / 4;
    }

    // ---- 私有辅助方法 ----

    private int toCharCount(Object obj) {
        if (obj == null) return 0;
        if (obj instanceof String) return ((String) obj).length();
        if (obj instanceof Map) {
            int count = 0;
            for (Map.Entry<Object, Object> entry : ((Map<Object, Object>) obj).entrySet()) {
                count += toCharCount(entry.getKey());
                count += toCharCount(entry.getValue());
            }
            return count;
        }
        if (obj instanceof List) {
            int count = 0;
            for (Object item : (List<Object>) obj) {
                count += toCharCount(item);
            }
            return count;
        }
        return obj.toString().length();
    }

    private String buildSummaryPrompt(List<Map<String, Object>> messages) {
        StringBuilder sb = new StringBuilder();
        sb.append("请将以下对话历史压缩为简洁摘要，保留关键进度、决策和待办事项：\n\n");
        for (Map<String, Object> msg : messages) {
            String role = (String) msg.getOrDefault("role", "unknown");
            Object content = msg.get("content");
            sb.append("[").append(role).append("]: ");
            if (content instanceof String) {
                sb.append(content);
            } else if (content instanceof List) {
                for (Object item : (List<Object>) content) {
                    if (item instanceof Map) {
                        Map<Object,Object> block = (Map<Object,Object>) item;
                        String type = (String) block.getOrDefault("type", "");
                        if ("text".equals(type)) {
                            sb.append(block.getOrDefault("text", ""));
                        } else if ("tool_use".equals(type)) {
                            sb.append("[调用工具: ").append(block.getOrDefault("name", "")).append("]");
                        } else if ("tool_result".equals(type)) {
                            String c = String.valueOf(block.getOrDefault("content", ""));
                            // 截断过长的工具结果
                            if (c.length() > 200) c = c.substring(0, 200) + "...";
                            sb.append("[工具结果: ").append(c).append("]");
                        }
                    }
                }
            }
            sb.append("\n");
        }
        return sb.toString();
    }
}
